render(() => {
    const radioButtons = [
        { title: 'Нет файла', extension: 'Нет файла' },
        { title: 'Пример.docx', extension: 'DocX' },
        { title: 'Пример.pdf', extension: 'PDF' },
        { title: 'Пример.xls', extension: 'XLS' },
        { title: 'Пример.1c', extension: '1C' },
        { title: 'Фото газеты.jpg', extension: 'Img' },
        { title: 'Пример.fig', extension: 'Другой тип' },
        { title: '2 файла', extension: 'Несколько файлов' },
    ];

    const [status, setStatus] = React.useState('INITIAL');
    const [title, setTitle] = React.useState('Прикрепите файл');
    const [checked, setChecked] = React.useState(0);
    const [progressBar, setProgressBar] = React.useState(0);
    const [switchChecked, setSwitchChecked] = React.useState(false);

    const handleChange = (index) => () => {
        setChecked(index);
        setProgressBar(0);
        setTitle(radioButtons[index].title);
        setStatus(index === 0 ? 'INITIAL' : 'UPLOADED');
    };

    const handleDelete = () => {
        setChecked(0);
        setTitle(radioButtons[0].title);
        setStatus('INITIAL');
    };

    const handleSwitchChange = () => {
        setSwitchChecked((prev) => !prev);
    };

    const isImg = radioButtons[checked].extension === 'Img';

    return (
        <React.Fragment>
            <div style={{ maxWidth: 360 }}>
                <FileUploadItem
                    title={title}
                    subtitle='Нет файла'
                    uploadStatus={status}
                    size={2097152} // 2mb
                    uploadDate={new Date().toLocaleDateString()}
                    progressBar={progressBar}
                    {...(checked !== 0 && { showDelete: true })}
                    {...(isImg && { imageUrl: './images/gagarin_yu_a.png' })}
                    {...(switchChecked && { iconStyle: 'colored' })}
                    onDelete={handleDelete}
                >
                    <FileUploadItem.StatusControl />
                    <FileUploadItem.Content />
                    <FileUploadItem.Actions />
                </FileUploadItem>
            </div>
            <Gap size={20} />
            Контент
            <Gap size={12} />
            {radioButtons.map((button, index) => (
                <React.Fragment key={button.title}>
                    <Radio
                        key={button.title}
                        block={true}
                        size={24}
                        onChange={handleChange(index)}
                        checked={checked === index}
                        label={button.extension}
                    />
                    <Gap size={12} />
                </React.Fragment>
            ))}
            <Gap size={20} />
            <Divider />
            <Gap size={20} />
            <Switch checked={switchChecked} label='Цветные иконки' onChange={handleSwitchChange} />
        </React.Fragment>
    );
});

render(() => {
    const [status, setStatus] = React.useState('INITIAL');
    const [title, setTitle] = React.useState('Прикрепите файл');
    const [progressBar, setProgressBar] = React.useState(0);
    const [isProgressKnown, setIsProgressKnown] = React.useState(false);
    const [error, setError] = React.useState('');

    const isUploading = status === 'UPLOADING' || status === 'LOADING';
    const subtitle = isUploading ? 'Загружается' : 'Нет файла';

    const distance = 100;
    const duration = 500;
    const spinnerDuration = 5000;
    let startAnimation = null;

    const resetState = () => {
        setError('');
        setProgressBar(0);
        setStatus('INITIAL');
    };

    const measure = (timestamp, status, isSpinner = false) => {
        if (!startAnimation) {
            startAnimation = timestamp;
        }

        const elapsed = timestamp - startAnimation;
        const currentDuration = isSpinner ? spinnerDuration : duration;

        if (isSpinner) {
            if (elapsed < currentDuration) {
                return requestAnimationFrame((t) => measure(t, status, isSpinner));
            }
        } else {
            const progress = elapsed / currentDuration;
            const progressValue = progress * distance;
            setProgressBar(progressValue);

            if (progress < 1) {
                return requestAnimationFrame((t) => measure(t, status, isSpinner));
            }
        }

        if (status === 'SUCCESS') {
            setStatus(status);
        } else if (status === 'ERROR') {
            setStatus('ERROR');
            setError('Описание первой ошибки');
        } else if (status === 'MULTI_ERROR') {
            setStatus('ERROR');
            setError(['Описание первой ошибки', 'Описание второй ошибки']);
        }
    };

    const startUpload = (finalStatus, errorMessage) => {
        setError('');
        setProgressBar(0);
        setTitle('Пример.docx');

        if (!isProgressKnown) {
            setStatus('LOADING');
            requestAnimationFrame((t) => measure(t, finalStatus, true));
        } else {
            setStatus('UPLOADING');
            requestAnimationFrame((t) => measure(t, finalStatus));
        }
    };

    const handleSuccessClick = () => startUpload('SUCCESS');
    const handleError = () => startUpload('ERROR', 'Описание первой ошибки');
    const handleMultiError = () =>
        startUpload('MULTI_ERROR', ['Описание первой ошибки', 'Описание второй ошибки']);

    const handleToggleChange = () => {
        setIsProgressKnown((prev) => !prev);
        resetState();
    };

    return (
        <React.Fragment>
            <FileUploadItem
                title={title}
                subtitle={subtitle}
                uploadStatus={status}
                progressBar={isProgressKnown ? progressBar : undefined}
                progressBarAvailable={isProgressKnown}
                uploadDate='22.07.2024'
                size={2097152} // 2mb
                error={error}
            >
                <FileUploadItem.StatusControl />
                <FileUploadItem.Content />
                <FileUploadItem.Actions />
            </FileUploadItem>
            <Gap size={20} />
            <div>
                <Button size={32} onClick={handleSuccessClick}>
                    Успех
                </Button>
                <Gap size={8} direction='horizontal' />
                <Button size={32} onClick={handleError}>
                    Ошибка
                </Button>
                <Gap size={8} direction={isMobile() ? 'vertical' : 'horizontal'} />
                <Button size={32} onClick={handleMultiError}>
                    Несколько ошибок
                </Button>
            </div>
            <Gap size={20} />
            <Switch
                checked={isProgressKnown}
                label='Известен прогресс загрузки'
                onChange={handleToggleChange}
            />
        </React.Fragment>
    );
});

